def build_error_details(
    exception,
    method_name,
    service_state,
    request_info=None,
    additional_context=None,
):
    """Build comprehensive error details for debugging."""
    exc_type, exc_value, exc_tb = sys.exc_info()

    # Get full stack trace
    stack_trace = traceback.format_exception(exc_type, exc_value, exc_tb)

    # Get local variables from the frame where the exception occurred
    local_vars = {}
    if exc_tb:
        tb = exc_tb
        while tb.tb_next:
            tb = tb.tb_next
        frame = tb.tb_frame
        for key, value in frame.f_locals.items():
            try:
                local_vars[key] = repr(value)[:500]  # Limit size
            except Exception:
                local_vars[key] = "<unable to repr>"

    error_details = {
        "error_type": type(exception).__name__,
        "error_message": str(exception),
        "method_name": method_name,
        "timestamp": datetime.utcnow().isoformat(),
        "stack_trace": "".join(stack_trace),
        "local_variables": local_vars,
        "request_info": request_info,
        "service_state_snapshot": service_state.get_snapshot(),
        "python_version": sys.version,
        "pid": os.getpid(),
        "thread_id": threading.current_thread().ident,
        "thread_name": threading.current_thread().name,
        "additional_context": additional_context or {},
    }

    return error_details


